mapper.select:
SELECT calendar_event_id, user_goal_id, calendar_event_title,
       calendar_event_start_time, calendar_event_end_time, calendar_event_is_done
FROM calendar_event
WHERE user_id = #{userId}
   OR chat_room_id IN (
    SELECT chat_room_id
    FROM chat_room_user
    WHERE user_id = #{userId}
)
